var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 산업 지구, <color=#ffd34c>본선 리그 개최 중</color>","JPN":"シャレード産業地区、<color=#ffd34c>本戦リーグ開催中</color>","ENG":"Charade Industrial District, <color=#ffd34c>Gauntlet elimination rounds ongoing</color>","TWN":"查雷德工業區，<color=#ffd34c>舉行決賽中</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"……앞으로 경기 시작까지 10분!","JPN":"……試合開始まであと10分！","ENG":"...10 minutes until the match!","TWN":"……距離比賽開始還有10分鐘！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"산업 지구를 무대로 펼쳐지는 리그 준 결승전!","JPN":"産業地区を舞台に繰り広げられるリーグ準決勝戦！","ENG":"The stage for the semi-finals is none other than the industrial district!","TWN":"以工業區為舞台展開的聯賽準決賽！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"카나리아 스쿼드가 도착하기 전에 방어팀인 팩토리의 멤버들부터 빠르게 살펴볼까!","JPN":"カナリア・スクワッドが到着する前に防御チームのファクトリーのメンバー紹介をしちゃうぞ！","ENG":"Before Canary Squad gets here, let's go take a peek at the defending team, Factory, and its members!","TWN":"在金絲雀小隊抵達之前，先看看防守方工業隊的成員吧！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"작년에는 아쉽게 16강에서 떨어지고 말았던 팩토리!","JPN":"去年は惜しくもベスト16で敗退してしまったファクトリー！","ENG":"Factory only made it to pre-quarterfinals last year!","TWN":"去年工業隊很遺憾地沒能進入16強！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하지만 올해에는 이를 갈고 준비했다! 작년보다 훨씬 기량이 향상된 모습을 보여주면서…… ","JPN":"しかし今年はリベンジに燃え準備してきた！　去年よりずっとパワーアップした姿を見せ…… ","ENG":"But they seem to have prepared a lot for this year! They showed so much improvement over last year, and...","TWN":"但他們今年做好萬全準備！技術也比去年提升不少……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"엥?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"뭐야? 지난 경기랑 엔트리가 전혀 다르잖아?","JPN":"何これ？　前回の試合とエントリーメンバーが全然違うじゃない？","ENG":"What? Their roster is completely different from their last match.","TWN":"怎麼回事？參賽選手名單和上次比賽完全不一樣欸？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■■</color> 아니 ㅋㅋㅋㅋ 기량이 너무 향상된 거 아님 ㅋㅋㅋㅋ??\\n<color=#ffd34c>■ ■</color> 잠깐, 쟤네들 팩토리 멤버가 아니잖아????\\n<color=#ffd34c>■■ ■</color> 애초에 사람이 맞기는 해? 몸 대부분이 기계 덩어리인데?\\n<color=#ffd34c>■■ ■</color> 미친, 저런 걸 상대로 싸워야 한다고? 말이 돼?\\n<color=#ffd34c>■■ ■</color> 장난하나! 사기도 작작 쳐야지!","JPN":"<color=#ffd34c>■■■■</color> えっｗｗｗｗパワーアップしすぎだろｗｗｗ\\n<color=#ffd34c>■ ■</color> ってかファクトリーのメンバーじゃなくね？？\\n<color=#ffd34c>■■ ■</color> そもそもこれ人間か？　身体のほとんどが機械の塊だぞ？\\n<color=#ffd34c>■■ ■</color> あんなのを相手に戦わないといけないの？　さすがにおかしくね？\\n<color=#ffd34c>■■ ■</color> こんなやり方、さすがに舐めてるだろ！","ENG":"<color=#ffd34c>■■■■</color> Sheesh. LOL. Isn't that too much of an improvement? LOL!\\n<color=#ffd34c>■ ■</color> Wait, they aren't Factory members.\\n<color=#ffd34c>■■ ■</color> Are they even human? They're basically machines with flesh!\\n<color=#ffd34c>■■ ■</color> OMG. Canary has to fight against that? No way that's possible.\\n<color=#ffd34c>■■ ■</color> You gotta be kidding me! This goes beyond just cheating!","TWN":"<color=#ffd34c>■■■■</color> 怎麼搞的？呵呵呵～技術也提升太多？呵呵呵呵\\n<color=#ffd34c>■ ■</color> 等等，他們根本不是工業隊的人吧？？？？\\n<color=#ffd34c>■■ ■</color> 他們確定是人類嗎？怎麼體型都跟浩克一樣？\\n<color=#ffd34c>■■ ■</color> 笑死，要跟那種大塊頭比？像話嗎？\\n<color=#ffd34c>■■ ■</color> 開什麼玩笑！會不會騙太大！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"어이, 형씨 늦어도 너무 늦는 거 같은데? 기다리다 목 빠지겠다고?","JPN":"おい、あんちゃん。さすがに遅すぎるんじゃないか？　これ以上待てねえぜ？","ENG":"Yo, my man. How much longer are we gonna have to wait? We've been waiting for hours.","TWN":"喂，哥，是不是來得有點晚？我等到花兒都要謝咧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"벌써 다 뒈져버려서 사이좋게 관속에 처박힌 건 아니겠지?","JPN":"すでに全員くたばって仲良くあの世にいるんじゃねえだろうな？","ENG":"They're not already dead in their coffins, are they?","TWN":"人不會已經躺在棺材裡了吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그럴 리 없어. 스키너가 올 거다.","JPN":"そんなはずはない。スキナーは来る。","ENG":"There's no way. Skinner will come.","TWN":"不可能，史金納會來的。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"스키너까지 죽었으면, 네놈들도 다 죽여버릴 거야.","JPN":"スキナーまで死んでいたら、貴様らを全員殺す。","ENG":"If Skinner is dead, I'll kill you myself.","TWN":"如果史金納死了，你們也別想活。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"로터스에 처박혀서 모래만 파먹고 살다보니 머리가 어떻게 됐나 본데.","JPN":"長いことロータスにぶち込まれていたせいで頭がイカれてるようだが。","ENG":"Did you lose your mind only eating sand while you were stuck in Lotus?","TWN":"你是不是在洛德斯關太久，關到腦袋有點不正常？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"이건 비즈니스일 뿐이야. 네 놈의 역겨운 욕정 따위 털끝만큼도 관심 없다.","JPN":"これはあくまでビジネスだ。お前の気色悪い欲情にはこれっぽちも興味はない。","ENG":"This is business. I'm not interested in your disgusting concupiscence.","TWN":"這只是交易而已。至於你這傢伙噁心的欲望，我是絲毫不感興趣。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그러니 죽고 싶지 않으면, 구더기답게 얌전히 처박혀서 닥치고 있는 게 좋을 거야.","JPN":"だから殺されたくなければ、ウジはウジらしく大人しく引っ込んでいろ。","ENG":"So if you don't want to die, be a good Maggot and shut up.","TWN":"所以如果你不想死，那最好是給我老實待著，蛆就該有蛆的樣子。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그래? 자신 있으면 어디 해보시지?","JPN":"ほう？　やれるものならやってみな。","ENG":"Oh, yeah? Then let's see what you got, eh?","TWN":"是嗎？你既然這麼有自信，何不試試？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"내가 너희와 같이 일하면서 아무 대책도 준비하지 않았을 것 같나?","JPN":"俺がお前らと仕事する上で、何の対策もしていないはずがないだろ？","ENG":"You think I didn't prepare any measures while working with you?","TWN":"你們覺得跟你們這樣的人合作，我會沒準備好對策嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"어디 죽일 테면, 죽여 봐.","JPN":"殺せるもんなら、殺してみろよ。","ENG":"Go on, kill me. I dare you.","TWN":"你有本事就殺了我。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"날 죽이면, 이 기생충이 너희 머릿속을 파고들어, 평생 죽으라는 명령을 속삭일 테니까.","JPN":"俺を殺せばこの寄生虫が貴様らの頭に入り込み、命が尽きるまで死ねという命令を囁き続けるだろうがな。","ENG":"You kill me, then this parasite will crawl into your head and whisper to you to kill yourself for the rest of your life.","TWN":"如果殺了我，這個寄生蟲就會鑽入你們的腦袋，然後一輩子在你們腦袋裡嗡嗡叫，叫你們去死。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"에헷!? 그거 아주 뿅가 죽을 거 같은데? 깡통! 나부터 해보면 안 될까?","JPN":"アハハッ！　それはなかなかガンギマリそうじゃないか？　おい、ボロ缶！　俺からやらせてくれよ！","ENG":"Hehe?! That sounds like fun! Tin Can! Can I go first?","TWN":"欸嘿？！酷欸？鐵桶！我能不能先試試？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_QM","text":{"KOREA":"이야~ 이거 다들 비주얼이 살벌하네.","JPN":"いや～こりゃ殺伐としたビジュアル揃いだな。","ENG":"Oof, don't they all look scary.","TWN":"哇喔～瞧你們長得一副凶神惡煞的樣子。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"으음?","JPN":"むむ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리 구면이지? 오랜만이야?","JPN":"私のこと覚えてる？　よ、久しぶり？","ENG":"We've met, haven't we? Long time no see.","TWN":"我們以前見過吧？好久不見了？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"스캐빈저들이 왜 샤레이드에 있나 했더니, 요즘 스캐빈저들은 건틀렛도 뛰나 봐?","JPN":"スカベンジャーたちがどうしてシャレードにいるのかと思ったら、今時のスカベンジャーはガントレットにも出るんだな？","ENG":"I was wondering why Scavengers were here in Charade. So, Scavengers now play in the Gauntlet too?","TWN":"我說清道夫怎麼會在查雷德，最近清道夫也開始參加聖鎧嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저 녀석들은 그때 컨테이너에서 봤던……!?","JPN":"あいつらは、あの時コンテナにいた……！？","ENG":"Aren't they the ones we saw at the container...?!","TWN":"那些傢伙是之前在箱子裡看到的……？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"약을 훔치려던 애송이들인가?","JPN":"薬を盗もうとしていたガキどもか？","ENG":"Are they the brats who tried to steal the drugs?","TWN":"是曾經試圖偷藥的小鬼？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L50_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"이거 꽤나 재밌겠군.","JPN":"これは面白い。","ENG":"This just got interesting.","TWN":"這下有趣囉。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};